import{_ as r,o as a,c as e,a9 as o}from"./chunks/framework.D4xYp1Zt.js";const p="/images/procrastination-matrix/HS1.png",n="/images/procrastination-matrix/HS2.png",i="/images/procrastination-matrix/HS3.png",s="/images/procrastination-matrix/HS3a.png",m="/images/procrastination-matrix/HS4.png",h="/images/procrastination-matrix/HS5.png",c="/images/procrastination-matrix/Reading1.png",l="/images/procrastination-matrix/Reading2.png",g="/images/procrastination-matrix/movie1.png",w="/images/procrastination-matrix/movie2.png",u="/images/procrastination-matrix/movie3.png",f="/images/procrastination-matrix/paper1.png",b="/images/procrastination-matrix/paper2.png",_="/images/procrastination-matrix/paper3.png",d="/images/procrastination-matrix/paper4.png",x="/images/procrastination-matrix/extension1.png",y="/images/procrastination-matrix/extension2.png",k="/images/procrastination-matrix/extension3.png",M="/images/procrastination-matrix/extension4.png",D="/images/procrastination-matrix/extension5-2.png",P="/images/procrastination-matrix/spread-thin.png",T="/images/procrastination-matrix/monkey-blog.png",Q="/images/procrastination-matrix/Eisenhower-Matrix.png",R="/images/procrastination-matrix/Eisenhower-Matrix-Actions.png",S="/images/procrastination-matrix/Procrastinators-Matrix1.png",q="/images/procrastination-matrix/FT1.png",W="/images/procrastination-matrix/Composer-Matrix.png",v="/images/procrastination-matrix/Business-Matrix.png",H="/images/procrastination-matrix/pie-chart.png",A="/images/procrastination-matrix/Disastinators-Matrix.png",B="/images/procrastination-matrix/self.png",I="/images/procrastination-matrix/Impostinators-Matrix.png",E="/images/procrastination-matrix/Successtinators-Matrix1.png",F="/images/procrastination-matrix/PDF-Button.png",C="/images/procrastination-matrix/plushies-ad-for-post.jpg",N="/images/procrastination-matrix/pinit_fg_en_rect_gray_20.png",V=JSON.parse('{"title":"The Procrastination Matrix","description":"","frontmatter":{"title":"The Procrastination Matrix","titleZh":"拖延矩阵","date":"2015-03-24T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2015/03/procrastination-matrix.html","slug":"procrastination-matrix"},"headers":[],"relativePath":"posts/procrastination-matrix.md","filePath":"posts/procrastination-matrix.md","lastUpdated":1782886257000}'),G={name:"posts/procrastination-matrix.md"};function J(L,t,U,$,j,K){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="拖延矩阵-·-the-procrastination-matrix" tabindex="-1">拖延矩阵 · The Procrastination Matrix <a class="header-anchor" href="#拖延矩阵-·-the-procrastination-matrix" aria-label="Permalink to &quot;拖延矩阵 · The Procrastination Matrix&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2015/03/procrastination-matrix.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2015/03/procrastination-matrix.html</a> · 2015-03-24</p></blockquote><h2 id="注-为了更好地理解这篇文章-你应该先读一下-wait-but-why-之前那篇关于拖延症的文章第一部分。" tabindex="-1"><em><strong>注:</strong> 为了更好地理解这篇文章,你应该先读一下 Wait But Why 之前那篇关于拖延症的<a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">文章</a>第一部分。</em> <a class="header-anchor" href="#注-为了更好地理解这篇文章-你应该先读一下-wait-but-why-之前那篇关于拖延症的文章第一部分。" aria-label="Permalink to &quot;***注:** 为了更好地理解这篇文章,你应该先读一下 Wait But Why 之前那篇关于拖延症的[文章](https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html)第一部分。*&quot;">​</a></h2><h2 id="pdf-版-我们把这篇文章做成了一个精致的-pdf-方便打印和离线阅读。点这里购买。-或者看预览。" tabindex="-1"><em><strong>PDF 版:</strong> 我们把这篇文章做成了一个精致的 PDF,方便打印和离线阅读。</em><em><a href="https://gum.co/wbw-proc3" target="_blank" rel="noreferrer">点这里购买。</a></em>*(或者看<a href="https://waitbutwhy.com/wp-content/uploads/2016/02/the-procrastination-matrix-preview.pdf" target="_blank" rel="noreferrer">预览</a>。)* <a class="header-anchor" href="#pdf-版-我们把这篇文章做成了一个精致的-pdf-方便打印和离线阅读。点这里购买。-或者看预览。" aria-label="Permalink to &quot;***PDF 版:** 我们把这篇文章做成了一个精致的 PDF,方便打印和离线阅读。**[点这里购买。](https://gum.co/wbw-proc3)**(或者看[预览](https://waitbutwhy.com/wp-content/uploads/2016/02/the-procrastination-matrix-preview.pdf)。)*&quot;">​</a></h2><p>高中那会儿,如果你问我是不是拖延症患者,我会说是。学校老师总爱在长期项目上给我们灌输那套「合理安排进度」的说教,而我呢,骄傲地做到了比我认识的几乎任何人都不「合理安排」。我从没错过任何截止日期,但所有事情都是在截止前一晚才动手。我是个<em>拖延症患者</em>。</p><p>但其实我不是。高中充斥着各种常规的截止日期和短期项目,就连长期项目也有子截止日期强行给你划分节奏。是有<em>几次</em>要命的时刻,但大多数情况下,我只是把一切都拖到最后一刻,因为我知道那样做多半也能做得不错——那何乐而不为呢。</p><p>我脑子里确实有一只<a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">即时满足猴 (Instant Gratification Monkey)</a><a href="#footnote-1-3539">1</a>,但它更多时候是可爱多过讨厌。截止日期不断逼近,我的<a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">恐慌怪兽 (Panic Monster)</a><a href="#footnote-2-3539">2</a>从未真正入睡,而猴子也心知肚明——它每天可以抢过方向盘玩一会儿,但真正管事的不是它。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/HS1.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt="HS1"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/HS2.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="HS2"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/HS3.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="HS3"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/HS3a.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="HS3a"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/HS4.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt="HS4"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/HS5.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt="HS5"></a></p><p>有一天,高中结束了,我作为一个「看起来还算正常的人」的生活也随之终结。大学不像高中。作业都是大工程,截止日期之间隔得老远,而且你不再是小孩了,课程也不会把你当小孩对待——没人强迫你安排什么进度。作为一个政治学专业的学生,我大部分课在四个月里就那么几篇论文、一次期中考、一次期末考,这意味着大多数时候,视野范围内根本看不到任何硬性截止日期。</p><p>由于没有了死线来占据它的注意力,我那个没法想太远的恐慌怪兽 (Panic Monster) 开始花大把时间在冬眠。而我的理性决策者 (Rational Decision-Maker),从来没意识到自己有多依赖恐慌怪兽,现在开始execute不了自己的计划了。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Reading1.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt="Reading1"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Reading2.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="Reading2"></a></p><p>恐慌怪兽睡得越久,那只猴子就越有底气。理性决策者作为大脑里唯一能把世界看清楚的成员,忧心忡忡——他知道大学的作业比高中大得多,给自己合理安排节奏不再是可以嗤之以鼻的事,而是必须做的事情。等死线快到的时候,他会对社交活动强硬地说不,但这解决不了根本问题。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/movie1.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="movie1"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/movie2.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt="movie2"></a><br><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/movie3.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt="movie3"></a></p><p>理性决策者只会越陷越深地绝望,只有当事情糟糕到最惨烈的时候,局面才会有所改变。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/paper1.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt="paper1"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/paper2.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt="paper2"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/paper3.png" target="_blank" rel="noreferrer"><img src="'+_+'" alt="paper3"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/paper4.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt="paper4"></a></p><p>不管一个决定在理性决策者看来多么显而易见,事情越来越清楚了——没有恐慌怪兽的帮助,他根本管不住那只猴子。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/extension1.png" target="_blank" rel="noreferrer"><img src="'+x+'" alt="extension1"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/extension2.png" target="_blank" rel="noreferrer"><img src="'+y+'" alt="extension2"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/extension3.png" target="_blank" rel="noreferrer"><img src="'+k+'" alt="extension3"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/extension4.png" target="_blank" rel="noreferrer"><img src="'+M+'" alt="extension4"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/extension5-2.png" target="_blank" rel="noreferrer"><img src="'+D+'" alt="extension5-2"></a></p><p>大学期间,我的 RDM 常常灰心丧气,但对我的「及时行乐猴」(Instant Gratification Monkey) 来说,那却是一场彻底的文艺复兴——它尝试了各种各样的活动,努力寻找自我。桌边就是一台雅马哈电子琴,猴子对弹钢琴的热情与日俱增。几乎可以说,每当我的 RDM 最用力跺脚催我干正事的时候,恰恰就是猴子最兴致勃勃地戴上耳机、一头扎进钢琴里几个小时的时候。</p><p>大学一结束,我兴奋得不得了——总算永远告别了正规教育,那玩意儿显然不适合我——于是我带着 1000 个雄心壮志、想做 1000 件事,一头闯进了世界。就等世界见识见识我吧。除了知识、技能和职业操守之外,我几乎能想到的东西我都有。</p><p>我的 RDM 对这事想了很多,他意识到猴子整个大学都在试图告诉他一件重要的事——我想成为一名<em>作曲家</em>。这显然是我最被吸引的东西,而现在,它终于要成为我每天<em>应该</em>做的事了。不用再和猴子搏斗了——它想要的它都能得到了。我参透了人生,我搬到洛杉矶去写电影配乐。</p><p>为了付房租,我开始在放学后给孩子们辅导作业或 SAT,选这份副业是因为它不会分散我成为下一个约翰·威廉姆斯 (John Williams) 的注意力。这个安排完美极了,我对音乐充满激情,事情也开始有了起色——然后最诡异的事情发生了。就在我确信自己找到了人生方向的时候,猴子开始了它自己的灵魂探索。每当 RDM 和我坐到钢琴前想写点东西——也就是猴子整个大学都<em>痴迷</em>的那件事——猴子就会耍脾气,拒绝加入我们。RDM 开始感到无助,就像大学时那样。</p><p>与此同时,猴子找到了新的兴趣——它开始迷上了我的<em>副业</em>。辅导工作进展顺利,推荐的人越来越多,虽然 RDM 一直坚持说我们的学生已经太多了,但猴子还是把每一个上门的新活儿都接了下来。很快,猴子开始想得更大,而且它没跟我们其他人商量,就擅自开始雇我的朋友们来帮我做辅导。RDM 一早醒来,满心想着扑到作曲上,结果整天都在打电话、埋头在表格里。猴子办起了公司。</p><p>我的大脑和我最后陷入了一种令人不快的无人地带。猴子拒绝让我们全心投入音乐事业,RDM 又拒绝拥抱猴子的新事业。我做了一堆事,但哪件都没有全力以赴。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/spread-thin.png" target="_blank" rel="noreferrer"><img src="'+P+'" alt="spread thin"></a></p><p>大概就在那时,我最好的朋友 Andrew 搬到了洛杉矶。Andrew 跟我不一样。他生活的一切都是生意,对追求任何艺术方面的事情毫无兴趣,而且自从五岁认识他以来,他的猴子就是个乖乖听话的小怂货。他搬过来之后,我们开始聊或许可以一起做点生意。在那之前,我的理智决策者 (RDM) 一直拒绝认真考虑做生意这回事,但和 Andrew 一起创业、真正全身心投入的前景很诱人——而且猴子显然对这事很上头,所以说不定<em>这个</em>才是我一直以来该做的事。我决定放手一搏,在我之前起步的基础上,我们一起创办了一家新的辅导公司。</p><p>RDM 仍然纠结要不要把音乐那边的事情暂停,但公司增长得很快,和 Andrew 一起做生意特别爽——就像和朋友一起玩一款复杂的策略游戏——RDM 终于开始觉得完全扎进生意里也没什么问题。</p><p>而这就是猴子开始成为一名狂热博主的信号。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/monkey-blog.png" target="_blank" rel="noreferrer"><img src="'+T+'" alt="monkey blog"></a></p><p>那时候我已经断断续续写博客写了几年,而生意刚起飞恰好就是猴子把这个新爱好全速开动起来所需要的契机,接下来几年里,我在业余时间写了几百篇博文。我每天都去上班,在公司的时候也算投入——但一个创业者本该在下班后做的事情,是让脑子里的齿轮继续转,反复琢磨战略,允许潜意识时不时把关键的顿悟砸到你头上,可我下班后想的全是下一篇博客写什么。</p><h2 id="到了-2013-年-andrew-和我决定搞点新东西时-我们看了看我的猴子-发现他总是那么沉浸在博客里-就想着说不定那个才是我一直以来该做的事——于是我们创办了-wait-but-why。andrew-会继续把我们的公司做大-而我则彻底一头扎进这个新项目里-把猴子渴望已久的东西完完整整地交给他。" tabindex="-1">到了 2013 年,Andrew 和我决定搞点新东西时,我们看了看我的猴子,发现他总是那么沉浸在博客里,就想着说不定<em>那个</em>才是我一直以来该做的事——于是我们创办了 Wait But Why。Andrew 会继续把我们的公司做大,而我则彻底一头扎进这个新项目里,把猴子渴望已久的东西完完整整地交给他。 <a class="header-anchor" href="#到了-2013-年-andrew-和我决定搞点新东西时-我们看了看我的猴子-发现他总是那么沉浸在博客里-就想着说不定那个才是我一直以来该做的事——于是我们创办了-wait-but-why。andrew-会继续把我们的公司做大-而我则彻底一头扎进这个新项目里-把猴子渴望已久的东西完完整整地交给他。" aria-label="Permalink to &quot;到了 2013 年,Andrew 和我决定搞点新东西时,我们看了看我的猴子,发现他总是那么沉浸在博客里,就想着说不定*那个*才是我一直以来该做的事——于是我们创办了 Wait But Why。Andrew 会继续把我们的公司做大,而我则彻底一头扎进这个新项目里,把猴子渴望已久的东西完完整整地交给他。&quot;">​</a></h2><p>在大学里是经典拖延症的东西,进入现实世界之后演变成了一种诡异的疯狂形式。在日常的、微观的层面上,那种「RDM 想做点事、猴子出来使坏」的老套路依然存在,但从更宏观的角度看,几乎像是我在<em>追着</em>猴子跑。在大学里被他彻底击溃之后,我开始怀疑,一开始就跟他对着干是不是我的错。他是从我内在某个原始的部分里长出来的,那么关注他的倾向、把它们当成我的指南针,难道不是理所当然的吗?</p><p>所以我就试着这么做——每当他不断地被某样东西吸引时,我最终会跟着他的引导,把生活围绕那件事来构建。但问题是,他几乎像是一个海市蜃楼——每当我到达他所在的地方时,他就不在那儿了。他跑到了别的地方。这就让人困惑了——他之前在那儿,是因为他真的想在那儿,还是仅仅因为那是「即时满足猴子 (RDM)」<em>不</em>在的地方?他到底有没有自己真正的热情,还是说他只是我内心里某个飘忽不定的邪恶唱反调者,使命就是阻止我用自己的天赋和精力去做任何伟大的事?</p><p>去年,我偶然看到一张小图,我觉得它掌握着解开这些问题的钥匙。它叫「艾森豪威尔矩阵 (Eisenhower Matrix)」:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Eisenhower-Matrix.png" target="_blank" rel="noreferrer"><img src="'+Q+'" alt="Eisenhower Matrix"></a></p><p>艾森豪威尔矩阵把你可能花时间做的任何事情放在两个维度上:一个维度从最紧急的任务到最不紧急的任务,另一个维度从至关重要到完全无关紧要——用这两条轴,把你的世界分成了四个象限。</p><p>这个矩阵因史蒂芬·柯维 (Stephen Covey) 的著名书籍 <a href="https://www.amazon.com/gp/product/1451639619/ref=as_li_tl?ie=UTF8&amp;camp=1789&amp;creative=390957&amp;creativeASIN=1451639619&amp;linkCode=as2&amp;tag=wabuwh00-20&amp;linkId=NWOAUWNGA6LU6OH3" target="_blank" rel="noreferrer">《高效能人士的七个习惯》(<em>The Seven Habits of Highly Effective People</em>)</a> 而广为流传,并以德怀特·艾森豪威尔 (Dwight Eisenhower) 总统的名字命名。艾森豪威尔以高产著称,柯维将此归功于他「要事第一」的时间安排态度。而对艾森豪威尔来说,「要事」永远是那些<em>重要</em>的事。他认为你应该把几乎所有时间都花在象限 1 和象限 2 里,他用每个象限一个以 D 开头的简单单词来实现这一点:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Eisenhower-Matrix-Actions.png" target="_blank" rel="noreferrer"><img src="'+R+'" alt="Eisenhower Matrix Actions"></a></p><p>这对德怀特·他妈的·艾森豪威尔来说棒极了。但你知道德怀特那颗光头里显然没有装着什么吗?一只无所不能的即时满足猴子。如果他有,他就会知道,一个拖延症患者的矩阵长这样:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Procrastinators-Matrix1.png" target="_blank" rel="noreferrer"><img src="'+S+'" alt="Procrastinator&#39;s Matrix"></a></p><p>如果你想知道任何关于象限 4 的信息——怎么走、哪里吃饭之类的——去问一个拖延症患者就行。他们就住在那儿。对一个非拖延症患者来说,象限 4 是一个消磨时光的快乐去处。忙完一整天的重要工作之后,窝在 Q4 里放松一下感觉棒极了——在这种情况下,Q4 有个名字:<a href="https://waitbutwhy.com/2013/11/how-to-beat-procrastination.html" target="_blank" rel="noreferrer">快乐游乐场 (The Happy Playground)</a>。但拖延症患者可不是在高效完成高级别工作的一天后才来 Q4 晃悠的——他们出现在这里的频率比这高得多,而且是被迫的,因为猴子把他们拽了过来,而与此同时理性决策者正在<em>苦苦哀求</em>他们离开。他们给 Q4 起了另一个名字:<a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">黑暗游乐场 (The Dark Playground)</a>。</p><p>至于象限 1 和 3——那两个<em>紧急</em>的象限——大多数拖延症患者时不时都会落到那儿去,通常是一身冷汗,恐慌怪兽 (Panic Monster) 就在他们脸边尖叫。Q1 和 Q3 让拖延症患者不至于流落街头。</p><p>然后就是象限 2。对拖延症患者来说,象限 2 是一片陌生的、遥远的异国土地。有点像亚特兰蒂斯,或者纳尼亚。他知道那是个重要的地方,他也尝试过很多次要去那儿,但有个大问题——猴子讨厌那地方,而恐慌怪兽又对它毫不关心。而这正是每次都能把拖延症患者打败的致命组合。</p><p>这之所以是灾难性的,是因为通往拖延症患者梦想的路——通往拓宽视野、探索真正潜能、完成让他真正引以为傲的工作的路——直接穿过象限 2。Q1 和 Q3 或许是人们求生的地方,但 Q2 才是人们茁壮成长、开花结果的地方。</p><p>不过,如果你是拖延症患者,你走运了。你袖子里还藏着一张王牌——一个大胆无畏、精力充沛、才华横溢的人,一个能像踩死一只蚂蚁一样轻松击败猴子的人:未来的你 (Future You)。</p><p>未来的你是拖延症患者最重要的盟友——他永远都在,永远挺你,不管发生什么。这事儿我可太有发言权了。未来的 Tim 是个了不起的家伙。</p><p>闹钟响了我又不想起床时,我就按贪睡键,把起床这活儿转包给未来的 Tim。我的待办清单分两部分——一个短的、简单的,是给我自己的;还有一个长的,写满了我根本无法想象自己会去做的事情,因为它们看起来都太恶心了。未来的 Tim 总是二话不说就把那部分揽下来。就算是最令人厌恶的社交义务,未来的 Tim 也毫无怨言。前不久我被邀请参加一个反馈会,评一部三个小时长的话剧,作者是个我几乎不认识的人——我当然完全没打算去,但直接拒绝又会觉得愧疚,于是我解释说我这几个月很忙,不过等今年夏天再办一次的话我非常乐意参加,反正那时候这就是未来的 Tim 的问题,不是我的了。</p><p>未来的 Tim 还有着我做梦都想拥有的自律和生活平衡。我这人从来不怎么爱运动——但未来的 Tim 办了健身卡,替我们俩把该跑的步都跑了,而且我特别喜欢未来的 Tim 那么热衷于做健康料理,因为我自己实在没时间。未来的 Tim 就是那种我们都想成为的人——我建议你自己去认识一下他,方法就是买他的书,因为他是个高产的作家。</p><p>不过未来的 Tim 在我生活中扮演的最重要角色,又把我们带回到艾森豪威尔矩阵 (Eisenhower Matrix)。命运巧妙地安排,未来的 Tim 几乎所有时间都待在那个我自己怎么也去不了的地方:至关重要的第二象限 (Quadrant 2)。未来的 Tim 是第二象限的看守人,每当我列出一堆重要待办事项,发现大部分都落在 Q2 时,我不必绝望,因为我知道未来的 Tim 会搞定它们。这可太好了,考虑到过去的 Tim,那个没用的混蛋,常常把我扔在多么惨烈的境地里:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/FT1.png" target="_blank" rel="noreferrer"><img src="'+q+'" alt="FT"></a></p><p>但未来的 Tim 尽管有种种美德,却有一个致命的缺陷,几乎毁掉了一切:他不存在。</p><p>原来未来的你和猴子对爱好的热情一样,都是海市蜃楼。我把最重要的计划都押在未来的 Tim 真实存在这件事上,可每次我终于走到那个本以为能找到未来的 Tim 的时间点,他都无影无踪——出现在那里的只有蠢货现在的 Tim。这就是未来的你最操蛋的地方——每当时间终于赶上他,他就不再是未来的你了,他成了现在的你,而现在的你根本没法完成你派给未来的你的那些任务,因为那些任务只有没有猴子的人才能干。你当初把它们分派给未来的你,就是因为他<em>没有</em>猴子——这才是重点。于是你干起了你一贯的把戏——把它们再次转派给未来的你,盼着下次时间追上未来的你时,他能真的存在。</p><p>正是这一点让我多年来无法全力以赴地面对生活。要做的重要事情通常住在 Q2,一个我很难去的地方,所以我会把多余的精力转投到某个热情的爱好上。猴子会对这些爱好超级上头,因为爱好按定义就在 Q4——猴子最爱待的地方。</p><p>所以当我本该追求作曲事业时,情况是这样的:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Composer-Matrix.png" target="_blank" rel="noreferrer"><img src="'+W+'" alt="Composer Matrix"></a></p><p>而当我决定“跟随猴子的引导”去搞事业时,我漏掉了关键的一点:“搞”事业意味着让事业成为我<em>应该做的事</em>,这就把它从一件<em>不重要</em>的事变成了一件<em>重要</em>的事——把“事业”从 Q4,猴子最爱的地方,搬到了 Q2,他最讨厌的地方。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Business-Matrix.png" target="_blank" rel="noreferrer"><img src="'+v+'" alt="Business Matrix"></a></p><p>我原以为切换到 Q2 之后猴子还会继续沉迷于生意上,这说明我根本不了解这只猴子。猴子的热情从来不是音乐,不是生意,也不是写博客——猴子的热情永远是 Q4。</p><h2 id="而且猴子真正喜欢-q4-的地方-也不是-q4-本身有什么特别的——而是第四象限不是第一象限或第二象限。猴子的核心驱动力就是做最轻松的事-它受不了那些「重要」的象限-因为重要象限意味着有压力——那里有东西要证明-你的行动有后果-赌注很高-你在朝着星辰射箭-这意味着你可能会射不中。猴子说-不了谢谢。在本该构思天才商业增长策略的时候写了-300-篇博客文章-并不是「轻松」在写起来不费力——而是轻松在没什么可赌的。赌注-才是人类真正难以承受的东西。" tabindex="-1">而且猴子<em>真正</em>喜欢 Q4 的地方,也不是 Q4 本身有什么特别的——而是<em>第四象限不是第一象限或第二象限</em>。猴子的核心驱动力就是做<em>最轻松</em>的事,它受不了那些「重要」的象限,因为重要象限意味着有压力——那里有东西要证明,你的行动有后果,赌注很高,你在朝着星辰射箭,<em>这意味着你可能会射不中</em>。猴子说,不了谢谢。在本该构思天才商业增长策略的时候写了 300 篇博客文章,并不是「轻松」在写起来不费力——而是轻松在没什么可赌的。赌注,才是人类真正难以承受的东西。 <a class="header-anchor" href="#而且猴子真正喜欢-q4-的地方-也不是-q4-本身有什么特别的——而是第四象限不是第一象限或第二象限。猴子的核心驱动力就是做最轻松的事-它受不了那些「重要」的象限-因为重要象限意味着有压力——那里有东西要证明-你的行动有后果-赌注很高-你在朝着星辰射箭-这意味着你可能会射不中。猴子说-不了谢谢。在本该构思天才商业增长策略的时候写了-300-篇博客文章-并不是「轻松」在写起来不费力——而是轻松在没什么可赌的。赌注-才是人类真正难以承受的东西。" aria-label="Permalink to &quot;而且猴子*真正*喜欢 Q4 的地方,也不是 Q4 本身有什么特别的——而是*第四象限不是第一象限或第二象限*。猴子的核心驱动力就是做*最轻松*的事,它受不了那些「重要」的象限,因为重要象限意味着有压力——那里有东西要证明,你的行动有后果,赌注很高,你在朝着星辰射箭,*这意味着你可能会射不中*。猴子说,不了谢谢。在本该构思天才商业增长策略的时候写了 300 篇博客文章,并不是「轻松」在写起来不费力——而是轻松在没什么可赌的。赌注,才是人类真正难以承受的东西。&quot;">​</a></h2><p>我开始为 Wait But Why 写文章时,就知道我想写拖延症。我需要试着把脑子里那些疯狂的东西表达出来。把这个艰巨任务甩给未来 Tim 一段时间之后,我终于咬牙<a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">写了</a>。</p><p>反响铺天盖地。除了两篇文章下面 1,300 多条评论之外,以下是我收到的读者邮件的分类:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/pie-chart.png" target="_blank" rel="noreferrer"><img src="'+H+'" alt="pie chart"></a></p><p>有<em>成千上万</em>封邮件。看来这整件事不只是我一个人的问题。</p><p>而且这些邮件不是那种「嘿我喜欢你的拖延症文章拜拜」的简短便条——而是<em>详尽</em>的、发自肺腑的。相当多的邮件提到那两篇文章让他们哭了。他们哭不是因为被我那些烂火柴人画感动了——他们哭是因为<em>他们读到的正是自己人生中最大的问题之一</em>。</p><p>发邮件的人背景千差万别,涵盖各个年龄、各种职业,来自世界上几乎所有国家。我收到过巴基斯坦一个 13 岁孩子的邮件,阿根廷一位中年教授的邮件,密西西比州一位 80 岁退休护士的邮件;还有德国的平面设计师、澳大利亚的作家、加纳的电影制作人、韩国的创业者。还有那些博士生——成群结队的博士生——他们在做终极的 Q2 任务。</p><p>从某种意义上说,这些人的问题都完全相同,也和我的一样——一只他们控制不了的「及时行乐猴 (Instant Gratification Monkey)」。但我读完他们每一封信之后注意到,这个问题对他们生活的破坏程度差异巨大,取决于各自处境中的几个关键事实。这种差别把给我发邮件的读者分成了三类:</p><p><strong>1) 灾难型拖延者 (The Disastinators)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Disastinators-Matrix.png" target="_blank" rel="noreferrer"><img src="'+A+'" alt="Disastinator&#39;s Matrix"></a></p><p>在所有拖延症患者中,灾难型拖延者的状况最糟糕。灾难型拖延者永久驻扎在第四象限,拖延彻底摧毁了他们的生活。一个拖延症患者通常出于以下两个原因之一成为灾难型拖延者:</p><p><strong>A) 他们的猴子不再害怕「恐慌怪兽 (Panic Monster)」,已经变得无所不能</strong></p><p><strong>B) 他们是普通的拖延症患者,但生活中完全没有外部截止日期或压力</strong></p><p>情况 A 极其黑暗,而从读者邮件中我得知,这并不罕见。这些人已经失去了做任何对自己重要之事的能力,要么在螺旋下坠,要么彻底放弃。</p><p>在情况 B 中,灾难型拖延者并不比其他人更严重,只是他们的处境和性格构成了一场灾难性的匹配。他们的生活和工作性质让恐慌怪兽根本没理由醒过来,而不幸的是,猴子并不害怕「自我厌恶怪兽 (Self-Loathing Monster)」。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/self.png" target="_blank" rel="noreferrer"><img src="'+B+'" alt="self"></a></p><p>结果就是灾难型拖延者永远什么都完成不了。给我发邮件的很多博士候选人都属于这一类。</p><p><strong>2) 冒牌型拖延者 (The Impostinators)</strong></p><p>我们还没怎么谈过第三象限,但它可能是所有象限中最危险的,也是冒牌型拖延者称王的地方。冒牌型拖延者的生活是这样的:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Impostinators-Matrix.png" target="_blank" rel="noreferrer"><img src="'+I+'" alt="Impostinator&#39;s Matrix"></a></p><p>冒牌型拖延者<em>看起来</em>很高效,但她其实是个冒牌货——一个戴着「高效人士」面具的拖延症患者。因为把所有工作时间都花在第三象限,她看起来很忙——她<em>确实</em>很忙——但她真正的目标却似乎从未有过多少进展。</p><p>冒牌型拖延者的猴子很聪明,第三象限就是猴子最狡猾的把戏。猴子知道,「理性决策者 (RDM)」可能很好骗,只要他花足够多的时间不待在第四象限的「黑暗游乐场 (Dark Playground)」里,就能被安抚。所以冒牌型拖延者的猴子会制造一场在第四象限和第三象限之间来回拉锯的战斗,而这套之所以奏效,是因为第三象限对冒牌型拖延者来说<em>感觉</em>很高效。这一切依赖于冒牌型拖延者的一个重大幻觉——「忙 = 高效」。</p><p>于是「伪装型 (Impostinator)」会花一整天回邮件、跑腿、打电话、整理清单和日程、参加会议等等——如果她的评判标准是「今天在黑暗游乐场之外待了多久」,那她简直是大获全胜。但一天结束时,她感受到的那种满足感总带着一丝空虚,幸福游乐场从来没有真正快乐过。她可能骗自己相信自己过着高产的生活,但在潜意识里,她知道自己没在做该做的事。她的成就感底下,涌动着一股绝望的暗流。</p><p>实际上,她生活在一场宏大的、包罗万象的拖延里,由她的猴子精心策划。伪装型的猴子并不试图去打赢那场「做重要的事(Q2 里的东西)vs. 黑暗游乐场」的拔河比赛,而是把「理性决策者 (RDM)」骗到错误的战场上打仗,然后故意在这个战场上「输」给 RDM,这就让她以为自己干得挺不错。</p><p>伪装型面临的另一个难题是,Q3 有时会把自己伪装成 Q1。一个忙碌的伪装型往往相信自己焦头烂额忙的这些紧急工作<em>就是</em>重要的事,但问题就在艾森豪威尔本人说得最好的那句话上:</p><p><em>重要的事很少紧急,紧急的事很少重要。</em></p><p>换句话说,<em>Quadrant 1 常常根本不存在。</em> 并非总是如此,但对那些事业还没起步的人来说尤其可能是真的——因为通常当你真正重要的工作同时也很紧急时,意味着你已经有些不错的东西在推进了。这就制造了一个 catch-22:最需要靠紧迫感来推动自己做事的人——事业早期的拖延者——往往正是那些 Q1 完全空空如也的人。</p><p>时间越久,我越觉得所谓「超级忙」通常意味着 Q3 塞得满满的(往往还夹杂着太多 Q4 时间)。我知道,当我处在那种到处跟人说自己有多<em>忙</em>、多没时间搭理他们的状态时,几乎都是因为我被 Q3 的破事压垮了。真正掌控自己人生——真正在方向盘后面——的人,日程里往往有大把空隙。但社会对忙人报以微笑,「我觉得你手头太闲了」是一句侮辱,这就让伪装型看起来——常常也感觉起来——像是在正确地生活。虽然伪装型总会觉得自己比「灾难型 (Disastinator)」高级,但事实是,论在真正要紧的事情上的实际产出,两者是平级的。</p><p>这里的重要教训是:提防 Quadrant 3。Q3 会揪住你的衣领,把你推上一台「对各种事情做出反应」的跑步机。它不是一个能自我掌控的地方。稍不留神,Q3 就会把你的一生吸走。我知道,因为我人生的很大一部分时间都在当伪装型。</p><p>在给我发邮件的众多冒充拖延者里,最常见的职业是某种艺术家或者创业者。这两种情况下,你都是自己人生的老板,而那些重要的事——提升技能、拓展人脉、执行创意愿景——很少是紧急的。</p><p><strong>3) 成功拖延者 (Successtinators)</strong></p><p>我这辈子大部分时间都觉得自己没法把自己发挥到最大,但从一年半前开始做 Wait But Why 以来,我已经写了超过 25 万字——相当于 1000 页书——而且我做的事对我来说真的<em>有意义</em>。第一次,成就感不再伴随着一丝愧疚、空虚或绝望。我做到了!我是个<em>行动者</em>。</p><p>其实并不是。</p><p>现实是,我克服猴子问题的程度,并不比给我发邮件的那些冒充拖延者和灾难拖延者多出一丁点——最大的区别在于,我把自己置入了一种情境里,让我的人生有了一个又大又肥的第一象限。不是那种其实是第三象限伪装的假 Q1——而是真正的 Q1,而且塞得满满的。博客与真实的、活生生的读者之间那种亲密的关系——以及由此产生的压力——一旦读者多到能让恐慌怪兽感兴趣,博主的重要工作就会变成紧急工作。</p><p>对拖延者来说,这和博士学位那种情境是相反的,我之前说过那种情境对拖延者是灾难性的匹配。而定期给一群即时读者写作,则是与拖延者性格完美契合的例子,因为它把恐慌怪兽放在了最佳位置——让恐慌怪兽与他最重要的事业对齐。</p><p>当然,我的猴子仍然在用一切能用的方式肆虐我的整个人生——为了完成这篇文章,我熬了一个折寿的通宵。但他现在做的事和之前做的事有一个关键区别。在之前那些项目里,他把 Q4 时间用来追求真实的、有野心的项目——之所以能这么干,是因为理性决策者 (RDM) 也不完全确定<em>自己</em>想要什么,他会怀疑猴子那些分心之事是不是真的搞出了点名堂。但至少到目前为止,做 Wait But Why 这件事正中理性决策者的下怀,因为他实实在在花了很多时间待在重要之线的上方,所以他对这项事业有了一种以前没有的<em>信念</em>。正因为如此,他会让猴子在 Q4 和 Q3 里跳踢踏舞,主要是因为他也没法阻止,但他<em>不会</em>让猴子用他的时间去搞任何<em>严肃</em>的事。</p><p>我并没有征服拖延症,但至少目前,我处于拖延者情境里最不坏的那种——我是个成功拖延者。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Successtinators-Matrix1.png" target="_blank" rel="noreferrer"><img src="'+E+'" alt="Successtinator&#39;s Matrix"></a></p><p>「成功拖延症患者」(Successtinator) 已经为自己的问题找到了某种「近似解决方案」,但那方案通常并不美观,往往并不健康,而且通常无法持续。它是给一台故障机器打上的精巧胶带,暂时勉强维持运转。</p><h2 id="我收到了大量来自「成功拖延症患者」的邮件-他们的模式高度一致-也和我目前的状况产生了共鸣。「成功拖延症患者」可以对自己的生活感到满意-但通常在生活之中并不那么快乐。原因在于-成为「成功拖延症患者」并不能让你成为一个真正的成功者。一个人在职业上做得出色-却以牺牲平衡、人际关系和健康为代价-这不叫成功。真正的成功意味着职业生活和生活方式都运转良好并且彼此和谐——而「成功拖延症患者」压力过大、时间被占满-常常完全被剥夺了「快乐游乐场」时间-而这可是幸福人生的关键组成部分。「成功拖延症患者」在职业可能性上通常也是受限的——第一象限里可以做出优秀的工作-但那往往更偏向维持层面的事。第二象限仍然是绝大多数职业成长和跳出框架思考发生的地方-而和所有拖延者一样-「成功拖延症患者」很少踏入第二象限。" tabindex="-1">我收到了大量来自「成功拖延症患者」的邮件,他们的模式高度一致,也和我目前的状况产生了共鸣。「成功拖延症患者」可以对自己的生活感到满意,但通常在生活<em>之中</em>并不那么快乐。原因在于:成为「成功拖延症患者」并不能让你成为一个真正的成功者。一个人在职业上做得出色,却以牺牲平衡、人际关系和健康为代价,这不叫成功。真正的成功意味着职业生活<em>和</em>生活方式都运转良好并且彼此和谐——而「成功拖延症患者」压力过大、时间被占满,常常完全被剥夺了「快乐游乐场」时间,而这可是幸福人生的关键组成部分。「成功拖延症患者」在职业可能性上通常也是受限的——第一象限里可以做出优秀的工作,但那往往更偏向<em>维持</em>层面的事。第二象限仍然是绝大多数职业成长和跳出框架思考发生的地方,而和所有拖延者一样,「成功拖延症患者」很少踏入第二象限。 <a class="header-anchor" href="#我收到了大量来自「成功拖延症患者」的邮件-他们的模式高度一致-也和我目前的状况产生了共鸣。「成功拖延症患者」可以对自己的生活感到满意-但通常在生活之中并不那么快乐。原因在于-成为「成功拖延症患者」并不能让你成为一个真正的成功者。一个人在职业上做得出色-却以牺牲平衡、人际关系和健康为代价-这不叫成功。真正的成功意味着职业生活和生活方式都运转良好并且彼此和谐——而「成功拖延症患者」压力过大、时间被占满-常常完全被剥夺了「快乐游乐场」时间-而这可是幸福人生的关键组成部分。「成功拖延症患者」在职业可能性上通常也是受限的——第一象限里可以做出优秀的工作-但那往往更偏向维持层面的事。第二象限仍然是绝大多数职业成长和跳出框架思考发生的地方-而和所有拖延者一样-「成功拖延症患者」很少踏入第二象限。" aria-label="Permalink to &quot;我收到了大量来自「成功拖延症患者」的邮件,他们的模式高度一致,也和我目前的状况产生了共鸣。「成功拖延症患者」可以对自己的生活感到满意,但通常在生活*之中*并不那么快乐。原因在于:成为「成功拖延症患者」并不能让你成为一个真正的成功者。一个人在职业上做得出色,却以牺牲平衡、人际关系和健康为代价,这不叫成功。真正的成功意味着职业生活*和*生活方式都运转良好并且彼此和谐——而「成功拖延症患者」压力过大、时间被占满,常常完全被剥夺了「快乐游乐场」时间,而这可是幸福人生的关键组成部分。「成功拖延症患者」在职业可能性上通常也是受限的——第一象限里可以做出优秀的工作,但那往往更偏向*维持*层面的事。第二象限仍然是绝大多数职业成长和跳出框架思考发生的地方,而和所有拖延者一样,「成功拖延症患者」很少踏入第二象限。&quot;">​</a></h2><p>这世界上有比拖延更严重的问题。贫困、疾病、精神障碍、毒品成瘾之类的事情,让拖延看上去简直就是一个特权阶层的问题——是给那些生活里没什么真正苦难的人拿来受折磨用的东西。</p><p>但如果一个怀疑者花几个小时读一读我收到的那一堆拖延相关的邮件,我想他会同意:这在非常非常多的人生里,是一个惨烈的问题。而且它不只是伤害拖延者本人——它伤害拖延者身边的人,把影响一层层扩散出去。</p><p>这也是整个世界的损失。每一个史蒂夫·乔布斯 (Steve Jobs)、约翰·列侬 (John Lennon)、J.K. 罗琳 (J.K. Rowling),或者任何以其才华丰富了我们生活的人的背后,都有成千上万拥有同等潜力的人,却因为把时间浪费在错误的象限里,从未为这个世界成就多少东西。</p><p>看待这件事的一种方式是:每个人的人生都有一定数量的「时间点数」,而你怎么「花」这些点数,取决于你自己。想想看,一个每周花 30 小时待在第二象限的人,和另一个每周只能挤出 2 小时第二象限时间的人,他们之间的差别有多大。因为对很多人来说,第二象限才是真正取得进步的地方,所以纵观一生,30 小时的那个人所完成的事,会是 2 小时那个人的 <em>15 倍</em>。而在现实里,这个倍数很可能比 15 还要大得多,因为进步是在进步的基础上叠加的,速率会加速(也就是说,如果乔布斯只投入 1/15 的高效时间,他成就的绝不会是他实际成就的 1/15——他很可能什么都成就不了)。一个普通人和一个非凡的人之间的区别,或许就归结于他们各自如何分配自己的时间点数。</p><h2 id="拨开迷雾" tabindex="-1"><strong>拨开迷雾</strong> <a class="header-anchor" href="#拨开迷雾" aria-label="Permalink to &quot;**拨开迷雾**&quot;">​</a></h2><p>如果我们想改善自己花时间点数的方式,第一步就是学会用一个清晰透亮的艾森豪威尔矩阵来看世界——也就是说,得把所有的自欺欺人都甩掉。我们需要给「紧急」和「重要」发展出经过深思熟虑的定义,这对每个人都不一样,而且需要深挖一个高度个人化的问题:「对我来说,最重要的是什么?」</p><p>Brett McKay 把「重要的任务」<a href="http://www.artofmanliness.com/2013/10/23/eisenhower-decision-matrix/" target="_blank" rel="noreferrer">定义</a>为<em>那些有助于我们长期使命、价值观和目标的事情</em>。这个定义宽泛而直接,是一个不错的核心句子,以后评估重要性的时候可以回过头来参考。</p><p>关于什么紧急、什么不紧急的思考过程,应该围绕「什么最重要」这个自我讨论展开。理想状态下,紧急<em>不应该</em>意味着「那个揪着我领子最狠的东西」——它应该被定义为:在你清单上的重要任务里,<em>哪些早做比晚做更能受益</em>。用这个定义,陪孩子肯定算紧急,而在典型的、跟截止日期挂钩的紧急定义下,它会被归为「不紧急」。换句话说,你的优先级顺序最好由你的 RDM 来定,而不是你的恐慌怪兽。智慧住在 RDM 里,而当那个没脑子的恐慌怪兽来决定什么紧急什么不紧急时,你就把 RDM 的智慧从这场游戏里踢出去了。</p><p>你可能还想收集一些关于你目前如何花时间点数的硬数据——把接下来一周的每小时都记录下来,看看每一个小时都落在四个象限的哪一格里(结果很可能会让你不太愉快地惊讶)。</p><h2 id="成为你自己大脑的老板" tabindex="-1"><strong>成为你自己大脑的老板</strong> <a class="header-anchor" href="#成为你自己大脑的老板" aria-label="Permalink to &quot;**成为你自己大脑的老板**&quot;">​</a></h2><p>一旦你对自己的艾森豪威尔矩阵以及它各条边界的位置感到清晰,你就得做那件难的事:掌控你在矩阵内部花时间点数的方式。这对一个拖延症患者来说,是人生最大的挑战。</p><p>掌控之后的回报显而易见。一个人如果能掌控自己花时间点数的方式,能完成的事情之多——同时还能保持一种平衡的生活方式——简直不可思议。而那些没有掌控力的人会把大部分时间点数丢进 Q3 和 Q4,感觉自己既没时间工作也没时间生活,与此同时几乎啥也没做成。时间点数的分配就是一切。</p><p>一个身处绝境的拖延症患者,可以通过一种蛮力方法,朝正确方向迈出半步:把自己的生活重新安排一下,让自己变成一个「成功拖延者 (Successtinator)」。我现在就在这个阶段,这比我之前的状态好太多了。</p><h2 id="但这就像雇个保镖-而不是自己学会打架。拖延症患者真正的目标必须是搞清楚怎么才能当上自己大脑的老板。拖延症患者的现实是-他的内在自我——他的理性决策者——理论上是他人生的特级大师-但实践中只是个观众。拖延症患者的-rdm-无助地随波逐流-被猴子和恐慌怪兽这些原始力量推来搡去-从一件事挪到另一件事。直到某一天-拖延症患者的-rdm-能靠自己的双脚-想什么时候走就什么时候走-从第四象限走到第二象限——在那之前-他都还没被治好。" tabindex="-1">但这就像雇个保镖,而不是自己学会打架。拖延症患者真正的目标必须是搞清楚怎么才能当上自己大脑的老板。拖延症患者的现实是:他的内在自我——他的理性决策者——理论上是他人生的特级大师,但实践中只是个观众。拖延症患者的 RDM 无助地随波逐流,被猴子和恐慌怪兽这些原始力量推来搡去,从一件事挪到另一件事。直到某一天,拖延症患者的 RDM 能靠自己的双脚,想什么时候走就什么时候走,从第四象限走到第二象限——在那之前,他都还没被治好。 <a class="header-anchor" href="#但这就像雇个保镖-而不是自己学会打架。拖延症患者真正的目标必须是搞清楚怎么才能当上自己大脑的老板。拖延症患者的现实是-他的内在自我——他的理性决策者——理论上是他人生的特级大师-但实践中只是个观众。拖延症患者的-rdm-无助地随波逐流-被猴子和恐慌怪兽这些原始力量推来搡去-从一件事挪到另一件事。直到某一天-拖延症患者的-rdm-能靠自己的双脚-想什么时候走就什么时候走-从第四象限走到第二象限——在那之前-他都还没被治好。" aria-label="Permalink to &quot;但这就像雇个保镖,而不是自己学会打架。拖延症患者真正的目标必须是搞清楚怎么才能当上自己大脑的老板。拖延症患者的现实是:他的内在自我——他的理性决策者——理论上是他人生的特级大师,但实践中只是个观众。拖延症患者的 RDM 无助地随波逐流,被猴子和恐慌怪兽这些原始力量推来搡去,从一件事挪到另一件事。直到某一天,拖延症患者的 RDM 能靠自己的双脚,想什么时候走就什么时候走,从第四象限走到第二象限——在那之前,他都还没被治好。&quot;">​</a></h2><p>如果你 Google 一下「如何停止拖延」,会找到大概 1000 篇文章,每篇都给出了很棒的建议教你怎么做。问题是这些文章都是写给正常人看的,而拖延症患者不是正常人。作为不正常的人,拖延症患者总是错觉自己是正常的,所以他们读了建议文章之后<em>以为</em>自己能把这些建议用到生活中。但结果并不是这样。</p><p>拖延症患者在能够按照好建议行动之前,得先获得控制权。一个赛车手可以接受全世界最好的教练指导,但如果比赛开始时,方向盘和踏板是别人在控制,那所有的指导都没用。</p><p>这就是为什么拖延症患者唯一能把方向盘握在自己手里的办法,就是让他的自我实现的预言——他的<a href="https://waitbutwhy.com/2013/11/how-to-beat-procrastination.html" target="_blank" rel="noreferrer"><em>剧本</em></a>——告诉他他能做到。而剧本只有通过现实世界的行动才能改变。典型的先有鸡还是先有蛋的难题。</p><p>在最深层次上,这归结为一场关于自信的较量。RDM 和猴子各自对如何花掉你的时间点数有自己的想法,而他俩当中谁更自信——谁更坚定地相信<em>自己</em>是这段关系里的老大——谁最终就会胜出。拖延症患者和非拖延症患者的区别很简单,就是拖延症患者的猴子和 RDM 都相信猴子是老大,而非拖延症患者的这对搭档都相信 RDM 是老板。</p><p>但无论这些自信程度感觉多么根深蒂固,猴子和 RDM 共享着同一个自信池,总和是固定的——一方的自信上升,另一方就下降——而这个平衡可以被最微小的变化撬动,你的剧本也会随之改变。</p><p>找出这个先有鸡还是先有蛋的悖论从哪里开始,是每个拖延者自己的功课。但有一个通用的起点,那就是尽可能保持<em>觉察</em>。觉察到什么是重要的,觉察到什么是紧急的,最重要的是——觉察到那只猴子。猴子不是你的朋友,永远都不会是。但它也是你脑袋里的一部分,不可能摆脱,所以养成留意它的习惯吧。早上醒来时,它在那儿。坐下来工作时,它在那儿。每当你最需要拿出全部胆量和毅力的时候,它就在那儿把你的胆量和毅力夺走。</p><h2 id="但它靠无意识才能茁壮成长。仅仅通过留意它-并对自己说「嗯-那猴子又准点出现了」-你就能开始把天平从它的默认状态那边扳过来一点。然后也许有一天-你会发现自己漫不经心地把猴子从方向盘上推下去-只用最简单的一句「不行猴子-现在不行」。你的生活将从此永远改变。" tabindex="-1">但它靠无意识才能茁壮成长。仅仅通过留意它,并对自己说「嗯,那猴子又准点出现了」,你就能开始把天平从它的默认状态那边扳过来一点。然后也许有一天,你会发现自己漫不经心地把猴子从方向盘上推下去,只用最简单的一句「不行猴子,现在不行」。你的生活将从此永远改变。 <a class="header-anchor" href="#但它靠无意识才能茁壮成长。仅仅通过留意它-并对自己说「嗯-那猴子又准点出现了」-你就能开始把天平从它的默认状态那边扳过来一点。然后也许有一天-你会发现自己漫不经心地把猴子从方向盘上推下去-只用最简单的一句「不行猴子-现在不行」。你的生活将从此永远改变。" aria-label="Permalink to &quot;但它靠无意识才能茁壮成长。仅仅通过留意它,并对自己说「嗯,那猴子又准点出现了」,你就能开始把天平从它的默认状态那边扳过来一点。然后也许有一天,你会发现自己漫不经心地把猴子从方向盘上推下去,只用最简单的一句「不行猴子,现在不行」。你的生活将从此永远改变。&quot;">​</a></h2><p>我很喜欢我收到的关于拖延的邮件,希望它们能继续来。但我总希望给我发邮件的人能彼此听到对方的故事。我鼓励任何愿意分享自己故事的人在评论里分享出来。</p><p><a href="https://gum.co/wbw-proc3" target="_blank" rel="noreferrer"><img src="'+F+'" alt="Buy the PDF"></a></p><h2 id="如果你喜欢这篇文章-也可以看看" tabindex="-1"><strong>如果你喜欢这篇文章,也可以看看:</strong> <a class="header-anchor" href="#如果你喜欢这篇文章-也可以看看" aria-label="Permalink to &quot;**如果你喜欢这篇文章,也可以看看:**&quot;">​</a></h2><p>Wait But Why 之前关于拖延的两篇文章 —— <a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">第一部分</a>、<a href="https://waitbutwhy.com/2013/11/how-to-beat-procrastination.html" target="_blank" rel="noreferrer">第二部分</a>。</p><p>生活就是今天一遍又一遍地重复 —— <a href="https://waitbutwhy.com/2013/11/life-is-picture-but-you-live-in-pixel.html" target="_blank" rel="noreferrer">生活是一幅画,但你活在一个像素里 (Life is a Picture, But You Live in a Pixel)</a></p><p>一张图提醒你明智地花掉自己的时间点数 —— <a href="https://waitbutwhy.com/2014/05/life-weeks.html" target="_blank" rel="noreferrer">你的一生用周来看 (Your Life in Weeks)</a></p><p>更深入地看看我们大脑里发生了什么,以及为什么觉察如此关键 —— <a href="https://waitbutwhy.com/2014/10/religion-for-the-nonreligious.html" target="_blank" rel="noreferrer">给非宗教人士的一种宗教 (A Religion for the Non-Religious)</a></p><p>看看大脑另一个部分里另一场动物斗争 —— <a href="https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html" target="_blank" rel="noreferrer">驯服猛犸象:你为什么该停止在意别人的看法 (Taming the Mammoth)</a></p><h2 id="既然它们要毁了你的人生-那不如抱着它们一起睡" tabindex="-1"><strong>既然它们要毁了你的人生,那不如抱着它们一起睡:</strong> <a class="header-anchor" href="#既然它们要毁了你的人生-那不如抱着它们一起睡" aria-label="Permalink to &quot;**既然它们要毁了你的人生,那不如抱着它们一起睡:**&quot;">​</a></h2><h2 id="" tabindex="-1"><a href="http://store.waitbutwhy.com/collections/plush-toys" target="_blank" rel="noreferrer"><img src="'+C+'" alt="plushies ad for post"></a> <a class="header-anchor" href="#" aria-label="Permalink to &quot;[![plushies ad for post](/images/procrastination-matrix/plushies-ad-for-post.jpg)](http://store.waitbutwhy.com/collections/plush-toys)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,可以订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章一发布我们就会发给你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><hr><ol><li><p>对于不熟悉的读者:「及时行乐猴 (Instant Gratification Monkey)」是你大脑里让你拖延的那部分——它是你身上一个原始的部分,活着就是为了把当下这一刻的舒适度最大化。想更多了解它,戳<a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">这里</a>。<a href="#note-1-3539">↩</a></p></li><li><p>对于不熟悉的读者:「恐慌怪兽 (Panic Monster)」是你大脑里那部分——一旦截止日期迫在眉睫,它就会醒过来并陷入癫狂。它是那只猴子唯一害怕的东西,也是一个拖延症患者最终能把事情做完的唯一原因。想更多了解它,戳<a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">这里</a>。<a href="#note-2-3539">↩</a></p></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2015/03/procrastination-matrix.html&amp;description=The%20Procrastination%20Matrix" target="_blank" rel="noreferrer"><img src="'+N+'" alt=""></a></p>',148)])])}const Y=r(G,[["render",J]]);export{V as __pageData,Y as default};
